The following api should return ib network by subnet id and ip_version.
But ip_version is None by default. 

def get_network_by_subnet_id(self, subnet_id, ip_version=None):
        ea = ib_objects.EA({'Subnet ID': subnet_id})

        if ip_version == 4 or ip_version is None:
            try:
                ib_network = ib_objects.NetworkV4.search(
                    self._grid_config.gm_connector,
                    network_view=network_view,
                    search_extattrs=ea)
            except ib_exc.InfobloxSearchError:
                ib_network = None

        if ip_version == 6 or ib_network is None:
            try:
                ib_network = ib_objects.NetworkV6.search(
                    self._grid_config.gm_connector,
                    network_view=network_view,
                    search_extattrs=ea)
            except ib_exc.InfobloxSearchError:
                ib_network = None

        return ib_network

Hi, I'm having another issue regarding populating an enum field from db values.

Here's an example:

```
class HostAdminForm(forms.ModelForm):
    class Meta:
        model = Host
        fields = '__all__'
        HOST_ROLES_SCHEMA['items']['properties']['categoryId'] = {
            'title': 'category',
            'type': 'string',
            'enum': [1, 2, 3, 4, 5],   #  ← We want to get the list of category ids from the db here
        }
        widgets = {
            'details': JSONEditorWidget(HOST_DETAILS_SCHEMA, collapsed=True),
        }
```

Any idea how we could proceed to do this ? Until now, we've asked our users to figure out what the id was and paste it in a text input  :/

