When I have a function returning a pointer, for some types (std::string*, int*) returning a nullptr segfaults, for others (char*, Class*) it returns None.

If it's a known limitation then take this issue as a feature request to handle nullptr in all cases.

Example:
rtest.cc
```cpp
#include <string>
#include <pybind11/pybind11.h>

namespace py = pybind11;

struct Custom { std::string s; };

int* r_int(bool nil) { static int v=12; return nil ? nullptr : &v; }
Custom* r_cust(bool nil) { static Custom v={"a"}; return nil ? nullptr : &v; }
std::string* r_str(bool nil) { static std::string v="b"; return nil ? nullptr : &v; }
char* r_char(bool nil) { static char v[]="c"; return nil ? nullptr : v; }

PYBIND11_PLUGIN(rtest) {
    py::module m("rtest", "");
    py::class_<Custom>(m, "Custom").def(py::init<>()).def_readwrite("s", &Custom::s);
    m.def("r_int", &r_int, py::return_value_policy::reference);
    m.def("r_cust", &r_cust, py::return_value_policy::reference);
    m.def("r_str", &r_str, py::return_value_policy::reference);
    m.def("r_char", &r_char, py::return_value_policy::reference);
    return m.ptr();
}
```
rtest.py
```py
from rtest import *

print r_int(False)
print r_cust(False)
print r_str(False)
print r_char(False)

print r_int(True)  # segfault
print r_cust(True)
print r_str(True)  # segfault
print r_char(True)
```

